var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그러니까……다른 세계의 나다. 이거로군?","JPN":"つまり……別の世界の俺。ということか？","ENG":"So... you're me from another world. Is that it?","TWN":"意思是……你是另一個世界的我？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"그렇지 않으면 이렇게 서로의 주먹을 맞고도 멀쩡한 녀석이 존재할 리 없잖아?","JPN":"俺の拳を受けておきながら無傷なやつは、他にいるはずないだろう？","ENG":"How else would we have been able to exchange blows like that and still be alive?","TWN":"要不然怎麼可能有人可以承受我們的拳頭？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"하하! 맞는 소리야.","JPN":"はは！　そのとおりだ。","ENG":"Hah hah! That's true.","TWN":"哈哈！說的沒錯。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"상당히 괜찮은 눈을 하고 있네. 나처럼.","JPN":"いい目つきだ。俺みたいに。","ENG":"I like that look in your eyes. It's just like mine.","TWN":"你的眼神很不錯，跟我一樣。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"이건 필시 상대를 찾아다니는 고독한 강자의 눈빛이지. 당신처럼.","JPN":"これは相手を探しまわる孤独な強者の眼差しだ。お前のように。","ENG":"They are the eyes of a lonely champion looking for a worthy opponent. Like you.","TWN":"這是高處不勝寒的強者眼神，跟你一樣。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"하하! 뭘 좀 아네~ 우리 세계에서도 이걸 몰라보는 녀석들이 많거든.","JPN":"はは！　わかってるね～俺の世界にもこれがわからないやつらが多くてさ。","ENG":"Hah hah! Exactly! Most people in my world can't even tell.","TWN":"哈哈！你懂欸～在我的世界裡很多人都不懂。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"우리 세계에서도 그런 녀석들은 쌔고 쌨지만……다 이 주먹 아래 무릎을 꿇었지.","JPN":"俺の世界でもそんなやつらばかりで……全員この拳で跪かせてきたがな。","ENG":"There were many strong opponents in my world... but I humbled them with my fist.","TWN":"在我的世界這種人也很多……不過他們都已經臣服在我的拳頭之下。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"동감이야. 역시 델타 세븐 최강의 카운터 제이크 워커 대령이로군.","JPN":"同感だよ。さすがデルタセブン最強のカウンター、ジェイク・ウォーカー大佐だな。","ENG":"Same here. So it really is Delta Seven's strongest Counter, Colonel Jake Walker.","TWN":"同意，不愧是第七三角洲的最強制裁者，傑克·沃克上校。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"당신도 마찬가지야, 제이시 워커.","JPN":"そっちもな、ジェイシー・ウォーカー。","ENG":"I can say the say for you, Jacey Walker.","TWN":"彼此彼此，潔西·沃克。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정말이지……! 못 봐주겠네 진짜!!","JPN":"もう……！　見てられないよ、本当に！！","ENG":"Oh, come on...! I can't take this anymore!!","TWN":"我真的是……！看不下去！！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"하하하하하하! 이렇게 기분이 상쾌한 적은 오랜만이야!","JPN":"はははははは！　こんなに清々しい気分になったのは久々だな！","ENG":"Hah hah hah hah! It's been a long time since I felt this refreshed!","TWN":"哈哈哈哈哈！好久沒有這麼痛快啦！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"하하하! 나도……응?","JPN":"ははは！　俺も……ん？","ENG":"Hah hah hah! Me t– Hmm?","TWN":"哈哈哈！我也……嗯？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"젠장, 침식체라고?","JPN":"くそっ、侵食体だと？","ENG":"Dammit, C.O.s?","TWN":"該死，是侵蝕體？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이곳은 얼마 전에 소탕을 마친 곳이야.","JPN":"ついこの間、ここは駆逐が完了したところだぞ。","ENG":"But this place was swept clean only a few days ago.","TWN":"這裡不是之前才掃蕩過嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"침식 쐐기들도 파괴해서 경계가 해제될 일만 남았다고.","JPN":"侵食楔も破壊したからもうすぐ警戒が解除されるのに。","ENG":"They even destroyed the Corrupted Wedges, so it's only a matter of time before the alert is lifted.","TWN":"而且侵蝕釘也都已經破壞掉，只差還沒解除警報而已。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"아무래도 내가 여기로 휘말릴 때 딸려온 녀석들인가 보네.","JPN":"どうやら俺がここに巻き込まれた時についてきたやつらのようだ。","ENG":"Guess they got sucked in along with me.","TWN":"應該是跟著我一起來的吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"태평하게 감상평만 늘어놓지 말고 어떻게 좀 해보라고!","JPN":"そんな感想はいいから早く何とかしてよ！","ENG":"Don't just stand there, do something!","TWN":"不要那麼冷靜地分析，還不快想想辦法！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"하하. 이것 참. 이런 걸 보면 우리 세계 실비아랑 행동거지가 똑같아.","JPN":"はは。こういうところをみると俺の世界のシルビアとまったく同じだな。","ENG":"Hah hah. She talks and acts just like the Sylvia in my world.","TWN":"哈哈，真是的，你的說話方式和我們世界的希爾維亞一模一樣呢。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"서로 착각할 만도 하겠어.","JPN":"そりゃ勘違いもするな。","ENG":"No wonder we got confused.","TWN":"我都要把你們給搞混了。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이거야 원. 내 원칙 첫 번째를 어긴 대가치곤 가혹하군.","JPN":"やれやれだぜ。俺の一つ目の原則を破った対価にしては過酷だな。","ENG":"Ugh. Seems like a steep price to pay for breaking my first principle.","TWN":"可惡，就算我打破我的第一個原則，但這個懲罰會不會太殘忍！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"존 메이슨 원칙 첫 번째. 다시는 군인과 엮이지 않는다.","JPN":"ジョン・メイソンの原則、その一。二度と軍人とは関わらない。","ENG":"John Mason's first principle. Never get involved with the military ever again.","TWN":"約翰·梅森原則一，絕對不再和軍人有交集。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};